import { useCallback } from "react";
import Particles from "react-tsparticles";
import { loadFull } from "tsparticles";

export default function LogisticsParticles(){

 const particlesInit = useCallback(async (engine) => {
   await loadFull(engine);
 }, []);

 const options = {

   fullScreen:{
     enable:true,
     zIndex:-1
   },

   background:{
     color:{
       value:"transparent"
     }
   },

   particles:{

     number:{
       value:70
     },

     color:{
       value:"#7ddf64"
     },

     links:{
       enable:true,
       color:"#c7fab6",
       distance:150,
       opacity:0.5
     },

     move:{
       enable:true,
       speed:1.5
     },

     size:{
       value:{min:2,max:6}
     }

   },

   interactivity:{

     events:{

       onHover:{
         enable:true,
         mode:"repulse"
       },

       onClick:{
         enable:true,
         mode:"push"
       }

     }

   }

 };

 return <Particles init={particlesInit} options={options} />;
}
